ALTER TABLE "Page" ADD COLUMN "wedding_session_types" TEXT;

UPDATE "Page"
SET "wedding_session_types" = '[{"title":"Getting Ready Session","image":"/uploads/ils-185.webp","description":"A documentary-style shoot capturing the anticipation and preparation before the ceremony.","items":["Bride and bridesmaids getting hair and makeup done","Groom and groomsmen putting on suits","Candid moments of nervous excitement","Detail shots of wedding attire, jewellery, and accessories"]},{"title":"Engagement Photoshoot","image":"/uploads/ils-195.webp","description":"A relaxed pre-wedding session — our chance to work together so you feel completely at ease in front of my camera before the big day.","items":["Casual and romantic outdoor locations","Urban settings in Glasgow or scenic Scottish landscapes","Perfect images for save-the-date cards"]},{"title":"Traditional Ceremony Coverage","image":"/uploads/ils-212.webp","description":"Discreet, full coverage of your ceremony — from the first arrival to the final kiss.","items":["Processional and recessional","Exchange of vows and rings","Reactions of family and guests","Formal family group portraits"]},{"title":"Couple''s Romantic Portraits","image":"/uploads/ils-197.webp","description":"A dedicated window of time during your day for relaxed, intimate portraits of just the two of you.","items":["Golden hour photography","Dramatic landscape backgrounds","Intimate, romantic poses"]},{"title":"Reception Reportage","image":"/uploads/ils-206.webp","description":"Pure documentary coverage of your reception — speeches, first dance, and everything in between.","items":["First dance","Speeches and toasts","Guest interactions","Dance floor energy"]},{"title":"Destination Wedding Coverage","image":"/uploads/ils-166.webp","description":"Wherever your love story takes you, I''ll be there with you to capture every moment.","items":["Full-day or multi-day coverage","Travel-friendly packages","Comprehensive documentation of destination events"]},{"title":"Sunrise / Sunset Session","image":"/uploads/ils-100.webp","description":"A dedicated golden-hour shoot at your venue or a nearby location for truly ethereal light.","items":["Golden hour timing","Romantic lighting conditions","Location selection and setup"]},{"title":"After-Wedding / Trash the Dress","image":"/uploads/ils-177.webp","description":"An adventurous post-wedding shoot in your attire — relaxed, creative, and free from the timeline pressure of the day itself.","items":["Creative outfit session","Adventurous locations","Fun and candid moments"]},{"title":"Micro-Wedding & Elopement Coverage","image":"/uploads/ils-154.webp","description":"Intimate celebrations for just the two of you — or a small circle of loved ones in a landscape that moves you.","items":["Intimate ceremony","Scenic couple portraits","Celebration with close loved ones"]}]'
WHERE "slug" = 'wedding-photography' AND ("wedding_session_types" IS NULL OR "wedding_session_types" = '');